import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as t,d as n}from"./app-75fed8c6.js";const i={},r=n(`<h2 id="perspectivecamera" tabindex="-1"><a class="header-anchor" href="#perspectivecamera" aria-hidden="true">#</a> PerspectiveCamera</h2><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> camera <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">THREE<span class="token punctuation">.</span>PerspectiveCamera</span><span class="token punctuation">(</span> <span class="token number">45</span><span class="token punctuation">,</span> width <span class="token operator">/</span> height<span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">1000</span> <span class="token punctuation">)</span><span class="token punctuation">;</span>
scene<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span> camera <span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="构造器" tabindex="-1"><a class="header-anchor" href="#构造器" aria-hidden="true">#</a> 构造器</h2><h3 id="perspectivecamera-fov-number-aspect-number-near-number-far-number" tabindex="-1"><a class="header-anchor" href="#perspectivecamera-fov-number-aspect-number-near-number-far-number" aria-hidden="true">#</a> PerspectiveCamera( fov : Number, aspect : Number, near : Number, far : Number )</h3><ul><li>fov — 摄像机视锥体垂直视野角度</li><li>aspect — 摄像机视锥体长宽比</li><li>near — 摄像机视锥体近端面</li><li>far — 摄像机视锥体远端面</li></ul><p>这些参数一起定义了摄像机的viewing frustum（视锥体）。</p><h2 id="属性" tabindex="-1"><a class="header-anchor" href="#属性" aria-hidden="true">#</a> 属性</h2><p>共有属性请参见其基类 Camera 。<br> 请注意，在大多数属性发生改变之后，你将需要调用.updateProjectionMatrix来使得这些改变生效。</p><h3 id="aspect-float" tabindex="-1"><a class="header-anchor" href="#aspect-float" aria-hidden="true">#</a> .aspect : Float</h3><p>摄像机视锥体的长宽比，通常是使用画布的宽/画布的高。默认值是1（正方形画布）。</p><h3 id="far-float" tabindex="-1"><a class="header-anchor" href="#far-float" aria-hidden="true">#</a> .far : Float</h3><p>摄像机的远端面，默认值是2000。</p><p>该值必须大于near plane（摄像机视锥体近端面）的值。</p><h3 id="filmgauge-float" tabindex="-1"><a class="header-anchor" href="#filmgauge-float" aria-hidden="true">#</a> .filmGauge : Float</h3><p>胶片尺寸，其默认值为35（毫米）。 这个参数不会影响摄像机的投影矩阵，除非.filmOffset被设置为了一个非零的值。</p><h3 id="filmoffset-float" tabindex="-1"><a class="header-anchor" href="#filmoffset-float" aria-hidden="true">#</a> .filmOffset : Float</h3><p>水平偏离中心偏移量，和.filmGauge单位相同。默认值为0。</p><h3 id="focus-float" tabindex="-1"><a class="header-anchor" href="#focus-float" aria-hidden="true">#</a> .focus : Float</h3><p>用于立体视觉和景深效果的物体的距离。 这个参数不会影响摄像机的投影矩阵，除非使用了StereoCamera。 默认值是10。</p><h3 id="fov-float" tabindex="-1"><a class="header-anchor" href="#fov-float" aria-hidden="true">#</a> .fov : Float</h3><p>摄像机视锥体垂直视野角度，从视图的底部到顶部，以角度来表示。默认值是50。</p><h3 id="isperspectivecamera-boolean" tabindex="-1"><a class="header-anchor" href="#isperspectivecamera-boolean" aria-hidden="true">#</a> .isPerspectiveCamera : Boolean</h3><p>Read-only标志，用于检查给定对象是否为PerspectiveCamera类型。</p><h3 id="near-float" tabindex="-1"><a class="header-anchor" href="#near-float" aria-hidden="true">#</a> .near : Float</h3><p>摄像机的近端面，默认值是0.1。</p><p>其有效值范围是0到当前摄像机far plane（远端面）的值之间。 请注意，和OrthographicCamera不同，0对于PerspectiveCamera的近端面来说不是一个有效值。</p><h3 id="view-object" tabindex="-1"><a class="header-anchor" href="#view-object" aria-hidden="true">#</a> .view : Object</h3><p>Frustum window specification or null. 这个值使用.setViewOffset方法来进行设置，使用.clearViewOffset方法来进行清除。</p><h3 id="zoom-number" tabindex="-1"><a class="header-anchor" href="#zoom-number" aria-hidden="true">#</a> .zoom : number</h3><p>获取或者设置摄像机的缩放倍数，其默认值为1。</p><h2 id="方法" tabindex="-1"><a class="header-anchor" href="#方法" aria-hidden="true">#</a> 方法</h2><p>共有方法请参见其基类Camera。</p><h3 id="clearviewoffset-undefined" tabindex="-1"><a class="header-anchor" href="#clearviewoffset-undefined" aria-hidden="true">#</a> .clearViewOffset () : undefined</h3><p>清除任何由.setViewOffset设置的偏移量。</p><h3 id="geteffectivefov-float" tabindex="-1"><a class="header-anchor" href="#geteffectivefov-float" aria-hidden="true">#</a> .getEffectiveFOV () : Float</h3><p>结合.zoom（缩放倍数），以角度返回当前垂直视野角度。</p><h3 id="getfilmheight-float" tabindex="-1"><a class="header-anchor" href="#getfilmheight-float" aria-hidden="true">#</a> .getFilmHeight () : Float</h3><p>返回当前胶片上图像的高，如果.aspect小于或等于1（肖像格式、纵向构图），则结果等于.filmGauge。</p><h3 id="getfilmwidth-float" tabindex="-1"><a class="header-anchor" href="#getfilmwidth-float" aria-hidden="true">#</a> .getFilmWidth () : Float</h3><p>返回当前胶片上图像的宽，如果.aspect大于或等于1（景观格式、横向构图），则结果等于.filmGauge。</p><h3 id="getfocallength-float" tabindex="-1"><a class="header-anchor" href="#getfocallength-float" aria-hidden="true">#</a> .getFocalLength () : Float</h3><p>返回当前.fov（视野角度）相对于.filmGauge（胶片尺寸）的焦距。</p><h3 id="setfocallength-focallength-float-undefined" tabindex="-1"><a class="header-anchor" href="#setfocallength-focallength-float-undefined" aria-hidden="true">#</a> .setFocalLength ( focalLength : Float ) : undefined</h3><p>通过相对于当前.filmGauge的焦距，设置FOV。</p><p>默认情况下，焦距是为35mm（全画幅）摄像机而指定的。</p><h3 id="setviewoffset-fullwidth-float-fullheight-float-x-float-y-float-width-float-height-float-undefined" tabindex="-1"><a class="header-anchor" href="#setviewoffset-fullwidth-float-fullheight-float-x-float-y-float-width-float-height-float-undefined" aria-hidden="true">#</a> .setViewOffset ( fullWidth : Float, fullHeight : Float, x : Float, y : Float, width : Float, height : Float ) : undefined</h3><ul><li>fullWidth — 多视图的全宽设置</li><li>fullHeight — 多视图的全高设置</li><li>x — 副摄像机的水平偏移</li><li>y — 副摄像机的垂直偏移</li><li>width — 副摄像机的宽度</li><li>height — 副摄像机的高度</li></ul><h3 id="updateprojectionmatrix-undefined" tabindex="-1"><a class="header-anchor" href="#updateprojectionmatrix-undefined" aria-hidden="true">#</a> .updateProjectionMatrix () : undefined</h3><p>更新摄像机投影矩阵。在任何参数被改变以后必须被调用。</p><h3 id="tojson-meta-object-object" tabindex="-1"><a class="header-anchor" href="#tojson-meta-object-object" aria-hidden="true">#</a> .toJSON (meta : Object) : Object</h3><p>meta -- 包含有元数据的对象，例如对象后代中的纹理或图像<br> 将摄像机转换为 three.js JSON Object/Scene format（three.js JSON 物体/场景格式）。</p>`,51),s=[r];function o(l,h){return e(),t("div",null,s)}const f=a(i,[["render",o],["__file","透视相机.html.vue"]]);export{f as default};
